export const version_info = {
  hash: "9564f1b",
  date: "21 Sep 2025 2:13",
  status:
    " M bin/version.ts\n M scripts/download-game-files.sh\n M scripts/setup-tests.sh\n M tests/test-server/static/test-game.html\n?? .crush/\n?? .env",
  version: "2.2.89",
};

export function getVersion() {
  const caution = version_info.status.length > 0 ? "⚠" : "";
  const date = version_info.status.length > 0 ? `${version_info.date} ` : "";
  return `Neptune's Pride Agent v${version_info.version} (${date}${caution}${version_info.hash})`;
}
